      "target": "partnership distribution",
      "hit_type": "glossary_term"
    },
    {
      "source": "中國內地",
      "target": "Mainland China",
      "hit_type": "glossary_term"
    }
  ],
  "fact_locks": [
    {
      "label": "percentage_10",
      "fact_type": "percentage",
      "source_value": "10%",
      "expected_forms": [
        "10%"
      ]
    }
  ],
  "current_group": {
    "group_id": "p14_g03",
    "lane": "body",
    "group_text": "香港在2020年2月初實施旅遊限制，來自中國內地訪港旅客的新業務銷售實際上已經停頓，導致新業務價值大幅\n下降。與上半年比較，我們的代理分銷來自本地客戶的業務於下半年錄得雙位數字的銷售增長，維持顯著的市場\n領導地位。夥伴分銷渠道的新業務價值顯著低於2019年，乃由於透過零售獨立財務顧問渠道的中國內地訪港旅客\n過往銷售比重較高。稅後營運溢利增長10%，受惠於續保保費強勁的增長及有利的理賠經驗。",
    "source_block_ids": [
      "p14_b11",
